try {
  const raw = $input.first().json;

  let msg  = null;
  let name = null;

  // --- Format A: n8n parsed message at root level ---
  if (raw.from && raw.type) {
    msg  = raw;
    name = raw.profileName || raw.name || null;
  }

  // --- Format B: raw WhatsApp Cloud API webhook ---
  if (!msg) {
    const val = raw?.entry?.[0]?.changes?.[0]?.value;
    if (val?.messages?.[0]) {
      msg  = val.messages[0];
      name = val.contacts?.[0]?.profile?.name || null;
    }
  }

  // --- Format C: message wrapped under a key ---
  if (!msg && raw.message?.from && raw.message?.type) {
    msg  = raw.message;
    name = raw.contact?.name || null;
  }

  // Nothing found or it's a status/delivery receipt
  if (!msg) return [];
  if (!msg.from) return [];
  if (msg.status) return [];           // delivery/read receipt
  if (!msg.type) return [];
  if (msg.type === 'reaction') return [];

  const typeMap = {
    text:     () => msg.text?.body || '',
    image:    () => '[Le client a envoyé une image]',
    audio:    () => '[Le client a envoyé un message vocal]',
    video:    () => '[Le client a envoyé une vidéo]',
    document: () => '[Le client a envoyé un document' + (msg.document?.filename ? ' : ' + msg.document.filename : '') + ']',
    sticker:  () => '[Le client a envoyé un sticker]',
    location: () => '[Le client a partagé sa localisation]',
  };

  const texte = (typeMap[msg.type] || (() => `[${msg.type}]`))();
  if (!texte || !texte.trim()) return [];

  const from = String(msg.from).trim();
  name = name || ('+' + from);

  return [{ json: { from, name, texte, type: msg.type } }];

} catch (e) {
  console.error('Extraire message error:', e.message);
  return [];
}

const data   = $input.first().json;
const msg    = $('Extraire message').first().json;
const orders = Array.isArray(data.orders) ? data.orders : [];

const statusLabel = {
  en_attente: 'En attente — traitement en cours',
  disponible: 'DISPONIBLE — prêt à récupérer ✅',
  recupere:   'Récupéré ✅'
};
const modeLabel = {
  avion:  'EXPRESS ✈️ (4–14 jours ouvrés)',
  bateau: 'ECO 🚢 (30–45 jours ouvrés)'
};

const fmt = n => typeof n === 'number' && n > 0
  ? n.toLocaleString('fr-FR') + ' FCFA'
  : (n === 0 ? '0 FCFA' : '—');

let contexteCommandes = '';

if (!data.found || orders.length === 0) {
  contexteCommandes = 'AUCUNE COMMANDE — ce numéro WhatsApp ne correspond à aucune commande enregistrée dans notre base de données.';
} else {
  const lignes = orders.map((o, i) => {
    const produits = (o.products || []).map(p =>
      `    • ${p.quantity}x ${p.name} (${p.condition})`
    ).join('\n');
    const date = o.created_at
      ? new Date(o.created_at).toLocaleDateString('fr-FR', { day:'2-digit', month:'long', year:'numeric' })
      : 'inconnue';
    return [
      `--- Commande ${i+1} / ${orders.length} ---`,
      `Référence  : ${o.order_number}`,
      `Date       : ${date}`,
      `Statut     : ${statusLabel[o.status] || o.status}`,
      `Transport  : ${modeLabel[o.delivery_type] || o.delivery_type}`,
      `Total      : ${fmt(o.total_amount)}`,
      `Versé      : ${fmt(o.deposit)}`,
      `Solde dû   : ${fmt(o.remaining_balance)}`,
      produits ? `Produits   :\n${produits}` : 'Produits   : —'
    ].join('\n');
  });
  contexteCommandes = lignes.join('\n\n');
}

// Detect intent from message text
const t = msg.texte.toLowerCase();
let intention = 'general';
if (/statut|état|où en|avancée|commande|colis|suivi|livr|récup|récupér/.test(t)) intention = 'suivi';
else if (/pay|acompte|versem|solde|reste|règlem|prix|factur|reçu/.test(t)) intention = 'paiement';
else if (/problème|réclamation|erreur|défectu|cassé|abîmé|manquan|mauvais|plainte/.test(t)) intention = 'reclamation';
else if (/bonjour|bonsoir|salut|hello|bonne journée|bonne soirée/.test(t)) intention = 'salutation';
else if (/merci|super|parfait|excellent|bien reçu|ok merci/.test(t)) intention = 'remerciement';
else if (/délai|quand|combien de temps|date|arrive|arriver|durée/.test(t)) intention = 'delai';

return [{
  json: {
    from: msg.from,
    name: msg.name,
    texte: msg.texte,
    type: msg.type,
    intention,
    contexteCommandes,
    hasOrders: data.found && orders.length > 0
  }
}];

const data = $input.first().json;
const ctx  = $('Préparer contexte + intention').first().json;

// Use AI response or fallback
const reponse = data.choices?.[0]?.message?.content?.trim()
  || 'Bonjour ! Merci pour votre message. Notre équipe vous répond dans les plus brefs délais. Pour toute urgence, contactez-nous directement au *+228 90 22 64 91* — *TOGOLESE* 🛒';

// Log usage for monitoring
const usage = data.usage || {};
console.log(`[IA] ${ctx.name} | intention: ${ctx.intention} | tokens: ${usage.total_tokens || '?'}`);

return [{ json: { from: ctx.from, reponse, intention: ctx.intention } }];
